return items.map(item => {

  /* ---------- 1. Termo ---------- */
  const termoOriginal = (item.json.TermoPesquisa || '').toString().trim();

  const termo = termoOriginal
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  /* ---------- 2. Extrações farmacêuticas ---------- */

  // dosagem: 500mg, 20ml, 1g
  const matchDose = termo.match(/([0-9]+(?:[.,][0-9]+)?\s*(mg|ml|g))/i);
  const dosagem = matchDose ? matchDose[1] : '';

  // quantidade: 30 comprimidos / 30cpr
  const matchQtd = termo.match(/(\d+)\s*(cpr|cp|comprimidos?|capsulas?)/i);
  const quantidade = matchQtd ? matchQtd[1] : '';

  // forma farmacêutica
  const forma =
    termo.includes('comprimid') || termo.includes('cpr') ? 'comprimido' :
    termo.includes('capsul') ? 'capsula' :
    termo.includes('xarope') ? 'xarope' :
    termo.includes('gel') ? 'gel' :
    termo.includes('spray') ? 'spray' :
    '';

  // princípio ativo (heurística simples baseada no texto)
  const palavras = termo
    .split(/\s+/)
    .filter(p => p.length > 3 && !p.match(/[0-9]/));

  const principio_ativo = palavras.length ? palavras[0] : '';

  /* ---------- 3. Domínio sugerido (APENAS para score, não para filtro) ---------- */
  let dominio_sugerido = 'indefinido';

  if (termo.match(/(mg|\d+mg|\d+ml|cpr|comprimid|capsul|xarope|dipirona|acetamol|ibuprofeno|amoxicilina)/)) {
    dominio_sugerido = 'medicamento';
  } else if (termo.match(/(shampoo|condicionador|hidratante|sabonete|creme|perfume|desodorante)/)) {
    dominio_sugerido = 'perfumaria';
  }

  /* ---------- 4. Score SQL (ranking, não bloqueio) ---------- */
  let score_sql = '';

  if (principio_ativo) {
    score_sql += ` + (CASE WHEN LOWER(Desc_Prd) LIKE '%${principio_ativo}%' THEN 1.0 ELSE 0 END)`;
  }

  if (dosagem) {
    score_sql += ` + (CASE WHEN LOWER(Desc_Prd) LIKE '%${dosagem}%' THEN 0.8 ELSE 0 END)`;
  }

  if (forma === 'comprimido') {
    score_sql += ` + (CASE WHEN Desc_Prd REGEXP 'CPR|CP ' THEN 0.4 ELSE 0 END)`;
  }

  if (quantidade) {
    score_sql += ` + (CASE WHEN Desc_Prd REGEXP '${quantidade}CPR|${quantidade} CPR' THEN 0.6 ELSE 0 END)`;
  }

  // penaliza combinações (ex: dipirona + cafeína)
  score_sql += ` - (CASE WHEN Desc_Prd LIKE '%+%' THEN 0.4 ELSE 0 END)`;

  /* ---------- 5. Saída ---------- */
  return {
    json: {
      termo: termoOriginal,
      principio_ativo,
      dosagem,
      quantidade,
      forma,
      dominio_sugerido,
      score_sql
    }
  };
});
